import './Rules.css';

const Rules = () => {
    return (
        <div className="rules-container">
            <div className="title-site">
                <h1>📽️ Regras do Clube do Cinema</h1>
            </div>
            <div className="rules-content">
                <p>Bem-vindos ao clube do cinema!</p>
                <hr/>
                <h2>📌 Regras</h2>
                <br/>
                <ul>
                    <li>🎡 Todas as semanas é feito um <strong>Wheel of Names</strong> com sugestões apenas de membros ativos.</li>
                    <li>📬 Cada membro ativo pode fazer apenas <strong>uma sugestão para a roda</strong> — conta sempre a mais recente.</li>
                    <li>🔗 As sugestões devem ser feitas no canal Discord <strong>#🍿recomendações</strong> e incluir o link do <strong>IMDb</strong> ou <strong>Letterboxd</strong>.</li>
                    <li>⏳ Se a tua sugestão for escolhida, só podes voltar a sugerir no mês seguinte.</li>
                    <li>📌 Se várias pessoas sugerirem o mesmo filme, ele entra várias vezes na roda (uma entrada por pessoa). Se for escolhido, todas essas pessoas ficam em pausa até ao próximo mês.</li>
                    <li>🚫 Não é permitido sugerir continuações sem que as prequelas tenham sido vistas no clube primeiro.</li>
                    <li>🛡️ Qualquer sugestão pode ser reprovada pela maioria dos membros ativos para evitar troll picks — nesse caso, a pessoa deve fazer uma nova sugestão.</li>
                    <li>🎟️ Tornas-te membro do clube ao veres o teu primeiro filme.</li>
                    <li>👤 Novos membros são considerados <strong>ativos</strong> durantes as primeiras 8 semanas. Para manter o estatuto de ativo, é preciso ter assistido a pelo menos 4 dos últimos 12 filmes.</li>
                </ul>
            </div>
        </div>
    );
}

export default Rules;
